1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	};
10	
11	interface Item {
12	  type: string;
13	}
14	
15	interface QuoteStep {
16	  op: "quote";
17	  items: Item[];
18	}
19	
20	interface Scenario {
21	  customer: { yearsWithMHPCO: number };
22	  steps: QuoteStep[];
23	}
24	
25	export function runScenario(input: unknown): unknown {
26	  const scenario = input as Scenario;
27	  const results = scenario.steps.map((step) => {
28	    const basePremium = step.items.reduce(
29	      (sum, item) => sum + (BASE_PREMIUM[item.type] ?? 0),
30	      0,
31	    );
32	    const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
33	    const premium = basePremium + firstInsurance + PROCESSING_FEE;
34	    return { premium };
35	  });
36	  return { results };
37	}
